css:
#_focus-toggle:focus,#_focus-toggle:focus-visible{outline-style:none!important;outline-width:3px!important;outline-color:rgb(107, 104, 98)!important;outline-offset:0px!important;box-shadow:none!important;background-color:rgb(252, 242, 250)!important;background-image:none!important;border-color:color(srgb 0.588235 0.239216 0.52549 / 0.12)!important;color:rgb(107, 104, 98)!important;transform:none!important;opacity:1!important;filter:none!important}
#searchopen:focus,#searchopen:focus-visible{outline-style:none!important;outline-width:3px!important;outline-color:rgb(0, 0, 0)!important;outline-offset:0px!important;box-shadow:rgba(40, 34, 28, 0.05) 0px 1px 2px 0px, rgba(40, 34, 28, 0.09) 0px 4px 10px -5px!important;background-color:rgba(0, 0, 0, 0)!important;background-image:linear-gradient(rgb(255, 255, 255) 0%, rgb(248, 245, 239) 100%)!important;border-color:rgb(232, 228, 220)!important;color:rgb(0, 0, 0)!important;transform:none!important;opacity:1!important;filter:none!important}
#cramopen:focus,#cramopen:focus-visible{outline-style:none!important;outline-width:3px!important;outline-color:rgb(0, 0, 0)!important;outline-offset:0px!important;box-shadow:rgba(40, 34, 28, 0.05) 0px 1px 2px 0px, rgba(40, 34, 28, 0.09) 0px 4px 10px -5px!important;background-color:rgba(0, 0, 0, 0)!important;background-image:linear-gradient(rgb(255, 255, 255) 0%, rgb(248, 245, 239) 100%)!important;border-color:rgb(232, 228, 220)!important;color:rgb(0, 0, 0)!important;transform:none!important;opacity:1!important;filter:none!important}
.sidebar .seg button:focus,.sidebar .seg button:focus-visible{outline-style:none!important;outline-width:3px!important;outline-color:rgb(150, 61, 134)!important;outline-offset:0px!important;box-shadow:color(srgb 0.588235 0.239216 0.52549 / 0.3) 0px 5px 16px -5px!important;background-color:rgba(0, 0, 0, 0)!important;background-image:linear-gradient(100deg, rgb(252, 242, 250), color(srgb 0.988235 0.94902 0.980392 / 0.45))!important;border-color:rgba(0, 0, 0, 0)!important;color:rgb(150, 61, 134)!important;transform:none!important;opacity:1!important;filter:none!important}
#tntrigger:focus,#tntrigger:focus-visible{outline-style:solid!important;outline-width:2px!important;outline-color:rgb(150, 61, 134)!important;outline-offset:1px!important;box-shadow:color(srgb 0.588235 0.239216 0.52549 / 0.15) 0px 0px 0px 3px, color(srgb 0.588235 0.239216 0.52549 / 0.2) 0px 0px 16px -4px!important;background-color:rgb(255, 255, 255)!important;background-image:none!important;border-color:rgb(232, 228, 220)!important;color:rgb(0, 0, 0)!important;transform:none!important;opacity:1!important;filter:none!important}
